import React from 'react';

export default function ResultsPanel({ result, onReset }) {
  const { filename, language, metrics, vulnerabilities } = result;

  const severityColor = {
    CRITICAL: '#a32d2d',
    HIGH: '#993c1d',
    MEDIUM: '#854f0b',
    LOW: '#3b6d11',
    INFO: '#185fa5',
  };

  const severityBg = {
    CRITICAL: '#fcebeb',
    HIGH: '#faece7',
    MEDIUM: '#faeeda',
    LOW: '#eaf3de',
    INFO: '#e6f1fb',
  };

  const riskColor = {
    CRITICAL: '#a32d2d',
    HIGH: '#993c1d',
    MEDIUM: '#854f0b',
    LOW: '#3b6d11',
    SAFE: '#0f6e56',
  };

  return (
    <div style={{ maxWidth: 800, margin: '2rem auto', padding: '0 1.5rem', fontFamily: 'Inter, sans-serif' }}>

      {/* Summary Cards */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(130px, 1fr))', gap: 12, marginBottom: 24 }}>
        {[
          { label: 'Security Score', value: metrics.security_score, color: metrics.security_score >= 80 ? '#0f6e56' : metrics.security_score >= 50 ? '#854f0b' : '#a32d2d' },
          { label: 'Risk Level', value: metrics.risk_level, color: riskColor[metrics.risk_level] || '#888' },
          { label: 'Vulnerabilities', value: metrics.vulnerability_count, color: metrics.vulnerability_count === 0 ? '#0f6e56' : '#a32d2d' },
          { label: 'Critical', value: metrics.critical_count, color: metrics.critical_count > 0 ? '#a32d2d' : '#0f6e56' },
          { label: 'High', value: metrics.high_count, color: metrics.high_count > 0 ? '#993c1d' : '#0f6e56' },
          { label: 'Lines', value: metrics.total_lines, color: '#185fa5' },
        ].map((card, i) => (
          <div key={i} style={{ background: '#f8f9fa', borderRadius: 8, padding: '1rem', textAlign: 'center', border: '1px solid #e5e5e5' }}>
            <div style={{ fontSize: 26, fontWeight: 700, color: card.color }}>{card.value}</div>
            <div style={{ fontSize: 12, color: '#888', marginTop: 3 }}>{card.label}</div>
          </div>
        ))}
      </div>

      {/* File Info */}
      <div style={{ background: '#f0fdf8', borderLeft: `4px solid ${riskColor[metrics.risk_level] || '#888'}`, borderRadius: '0 8px 8px 0', padding: '1rem 1.25rem', marginBottom: 24 }}>
        <div style={{ fontSize: 12, fontWeight: 700, color: riskColor[metrics.risk_level], marginBottom: 4, letterSpacing: '0.05em' }}>
          {filename} · {language} · RISK: {metrics.risk_level}
        </div>
        <div style={{ fontSize: 14, color: '#555' }}>
          {metrics.vulnerability_count === 0
            ? 'No vulnerabilities detected. This code passed all security checks.'
            : `Found ${metrics.vulnerability_count} vulnerabilit${metrics.vulnerability_count > 1 ? 'ies' : 'y'} — review and fix the issues below.`}
        </div>
      </div>

      {/* Vulnerabilities */}
      {vulnerabilities.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '2.5rem', border: '1px solid #e5e5e5', borderRadius: 10, background: '#fff' }}>
          <div style={{ fontSize: 40, marginBottom: 12 }}>✅</div>
          <p style={{ fontSize: 16, fontWeight: 600 }}>No vulnerabilities detected</p>
          <span style={{ fontSize: 13, color: '#888' }}>This code passed all security checks.</span>
        </div>
      ) : (
        <>
          <div style={{ fontSize: 12, fontWeight: 700, color: '#999', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 12 }}>
            Vulnerabilities Detected
          </div>
          {vulnerabilities.map((v, i) => (
            <div key={i} style={{ background: '#fff', border: '1px solid #e5e5e5', borderRadius: 10, padding: '1rem 1.25rem', marginBottom: 12 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 8 }}>
                <div style={{ fontSize: 15, fontWeight: 600 }}>{v.id} · {v.title}</div>
                <span style={{ fontSize: 11, fontWeight: 700, padding: '3px 9px', borderRadius: 4, background: severityBg[v.severity], color: severityColor[v.severity], whiteSpace: 'nowrap' }}>
                  {v.severity}
                </span>
              </div>
              <div style={{ fontSize: 13, color: '#555', lineHeight: 1.6, marginBottom: 10 }}>{v.description}</div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 10 }}>
                <span style={{ fontSize: 11, padding: '2px 8px', border: '1px solid #e5e5e5', borderRadius: 4, color: '#888' }}>{v.cwe_id}</span>
                {v.line_number && <span style={{ fontSize: 11, padding: '2px 8px', border: '1px solid #e5e5e5', borderRadius: 4, color: '#888' }}>Line {v.line_number}</span>}
                {v.cvss_score && <span style={{ fontSize: 11, padding: '2px 8px', border: '1px solid #e5e5e5', borderRadius: 4, color: '#888' }}>CVSS {v.cvss_score}</span>}
              </div>
              {v.recommendation && (
                <div style={{ background: '#f0fdf8', borderRadius: 6, padding: '0.75rem' }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: '#0f6e56', marginBottom: 4 }}>💡 RECOMMENDED FIX</div>
                  <div style={{ fontSize: 13, color: '#555', lineHeight: 1.5 }}>{v.recommendation}</div>
                </div>
              )}
            </div>
          ))}
        </>
      )}

      <button onClick={onReset} style={{ marginTop: 24, fontSize: 13, color: '#888', background: 'transparent', border: '1px solid #ddd', borderRadius: 6, padding: '7px 16px', cursor: 'pointer' }}>
        ↺ Analyze another file
      </button>
    </div>
  );
}
